<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;class Hunt extends Model{protected $guarded=[];protected $casts=['character_stats_snapshot'=>'array','enemy_count'=>'integer','rounds_count'=>'integer','character_health_before'=>'integer','character_health_after'=>'integer','started_at'=>'datetime','completed_at'=>'datetime','resolved_at'=>'datetime','combat_events_duration_ms'=>'integer','result_reveal_duration_ms'=>'integer','loot_reveal_duration_ms'=>'integer','playback_duration_ms'=>'integer','playback_speed_multiplier'=>'integer'];public function huntingSession(){return$this->belongsTo(HuntingSession::class);}public function character(){return$this->belongsTo(Character::class);}public function zone(){return$this->belongsTo(Zone::class);}public function enemies(){return$this->hasMany(HuntEnemy::class)->orderBy('position');}public function combatEvents(){return$this->hasMany(HuntCombatEvent::class)->orderBy('sequence');}public function reward(){return$this->hasOne(HuntReward::class);}}
